/* BTTag — removable pill label atom.
   Figma nodes 3050-6361 / 3050-6644.
   All colours via @btech/tokens CSS vars — no hex fallbacks. */

.bt-tag {
  display: inline-flex;
  align-items: center;
  gap: var(--space-xs);
  padding: var(--space-2xs) var(--space-xs);
  border-radius: var(--radius-sm);
  font-family: var(--typography-font-family-sans);
  font-size: var(--typography-font-size-xs);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  letter-spacing: 0;
  white-space: nowrap;
  color: var(--text-primary);
  cursor: default;
  user-select: none;
}

/* ── Default variant ── */
.bt-tag--default {
  background: var(--bg-subtler);
  border: none;
}
.bt-tag--default:hover {
  background: var(--bg-subtlest);
}

/* ── Outline variant ── */
.bt-tag--outline {
  background: transparent;
  border: 1px solid var(--border-secondary);
}
.bt-tag--outline:hover {
  background: var(--bg-subtle);
}

/* ── Close button ── */
.bt-tag__close {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 16px;
  height: 16px;
  flex-shrink: 0;
  cursor: pointer;
  color: var(--text-primary);
  background: none;
  border: none;
  padding: 0;
  line-height: 1;
}
.bt-tag__close:hover {
  opacity: 0.7;
}

/* ── Left icon slot ── */
.bt-tag__icon {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 16px;
  height: 16px;
  flex-shrink: 0;
}

/* ── Tag Group ── */
.bt-tag-group {
  display: flex;
  align-items: center;
}
.bt-tag-group--scroll {
  overflow-x: auto;
  flex-wrap: nowrap;
}
.bt-tag-group--wrap {
  flex-wrap: wrap;
}
.bt-tag-group--gap-default {
  gap: var(--space-xs);
}
.bt-tag-group--gap-loose {
  gap: var(--space-sm);
}

/**
 * BTTag — removable pill label atom.
 * Figma source: node 3050-6361.
 * Mirrors @btech/ui-vue BTTag one-to-one (same prop names, same render priority).
 *
 * ## Usage:
 * ```tsx
 * // Simple
 * <BTTag label="Flutter" />
 *
 * // With left icon + remove
 * <BTTag
 *   label="Vue"
 *   leftIcon={<CircleIcon size={16} />}
 *   onRemove={() => removeTag('Vue')}
 * />
 *
 * // Outline
 * <BTTag label="React" variant="outline" onRemove={handleRemove} />
 * ```
 */
import * as React from 'react';
import type { BTTagProps } from './BTTag.types';
import './BTTag.css';

export const BTTag = React.forwardRef<HTMLSpanElement, BTTagProps>(
  (
    {
      label,
      variant = 'default',
      leftIcon,
      onRemove,
      className,
      ...rest
    },
    ref,
  ) => {
    const classes = [
      'bt-tag',
      `bt-tag--${variant}`,
      className ?? '',
    ]
      .filter(Boolean)
      .join(' ');

    return (
      <span ref={ref} className={classes} data-testid="bt-tag" {...rest}>
        {leftIcon && <span className="bt-tag__icon">{leftIcon}</span>}
        <span className="bt-tag__label">{label}</span>
        {onRemove && (
          <button
            className="bt-tag__close"
            type="button"
            aria-label="Remove tag"
            onClick={(e) => { e.stopPropagation(); onRemove(); }}
          >
            <svg width="16" height="16" viewBox="0 0 16 16" fill="none" xmlns="http://www.w3.org/2000/svg">
              <path d="M8 1.5C4.41 1.5 1.5 4.41 1.5 8C1.5 11.59 4.41 14.5 8 14.5C11.59 14.5 14.5 11.59 14.5 8C14.5 4.41 11.59 1.5 8 1.5ZM11 10.29L10.29 11L8 8.71L5.71 11L5 10.29L7.29 8L5 5.71L5.71 5L8 7.29L10.29 5L11 5.71L8.71 8L11 10.29Z" fill="currentColor"/>
            </svg>
          </button>
        )}
      </span>
    );
  },
);

BTTag.displayName = 'BTTag';

import * as React from 'react';

/**
 * Props for {@link BTTag}.
 *
 * @example
 * ```tsx
 * <BTTag label="Flutter" />
 * <BTTag label="Vue" variant="outline" onRemove={() => removeTag('Vue')} />
 * <BTTag label="React" leftIcon={<CircleIcon size={16} />} onRemove={...} />
 * ```
 */
export interface BTTagProps {
  /** Text label shown inside the tag. */
  label: string;
  /** Visual style. @default 'default' */
  variant?: 'default' | 'outline';
  /** Optional 16×16 node rendered to the left of the label (slot). */
  leftIcon?: React.ReactNode;
  /** When provided, renders a close × button. Caller removes tag from list. */
  onRemove?: () => void;
  /** Additional CSS class names. */
  className?: string;
}

/**
 * Props for {@link BTTagGroup}.
 *
 * @example
 * ```tsx
 * <BTTagGroup
 *   items={tags}
 *   type="wrap"
 *   spacing="loose"
 *   onRemove={(item, index) => setTags(t => t.filter((_, i) => i !== index))}
 * />
 * ```
 */
export interface BTTagGroupProps {
  /** List of tags to display. */
  items: BTTagItem[];
  /** Variant applied to all tags. @default 'default' */
  variant?: 'default' | 'outline';
  /** Gap between tags. @default 'default' (4px) */
  spacing?: 'default' | 'loose';
  /** Layout mode. @default 'scroll' */
  type?: 'scroll' | 'wrap';
  /** Called when user clicks close on a tag. Caller must update items. */
  onRemove?: (item: BTTagItem, index: number) => void;
  /** Additional CSS class names. */
  className?: string;
}

export interface BTTagItem {
  /** Display text. */
  label: string;
  /** Optional unique key; falls back to label. */
  id?: string;
}

/**
 * BTTagGroup — layout wrapper for a list of BTTag items.
 * Figma source: node 3050-6644.
 *
 * ## Usage:
 * ```tsx
 * const [tags, setTags] = useState([
 *   { id: '1', label: 'Flutter' },
 *   { id: '2', label: 'React' },
 * ]);
 *
 * <BTTagGroup
 *   items={tags}
 *   type="wrap"
 *   spacing="loose"
 *   onRemove={(item, index) =>
 *     setTags(t => t.filter((_, i) => i !== index))
 *   }
 * />
 * ```
 */
import * as React from 'react';
import type { BTTagGroupProps } from './BTTag.types';
import { BTTag } from './BTTag';

export const BTTagGroup = React.forwardRef<HTMLDivElement, BTTagGroupProps>(
  (
    {
      items,
      variant = 'default',
      spacing = 'default',
      type = 'scroll',
      onRemove,
      className,
      ...rest
    },
    ref,
  ) => {
    const classes = [
      'bt-tag-group',
      `bt-tag-group--${type}`,
      `bt-tag-group--gap-${spacing}`,
      className ?? '',
    ]
      .filter(Boolean)
      .join(' ');

    return (
      <div ref={ref} className={classes} data-testid="bt-tag-group" {...rest}>
        {items.map((item, index) => (
          <BTTag
            key={item.id ?? item.label}
            label={item.label}
            variant={variant}
            onRemove={onRemove ? () => onRemove(item, index) : undefined}
          />
        ))}
      </div>
    );
  },
);

BTTagGroup.displayName = 'BTTagGroup';

export * from './BTTag.types';
export { BTTag } from './BTTag';
export { BTTagGroup } from './BTTagGroup';
